// Calcular promedio de estrellas
const records = $input.first().json.records || [];

if (records.length === 0) {
  return [{ json: {
    rating: 0,
    promedio: 0,
    total: 0,
    estrellas: '☆☆☆☆☆',
    mensaje: 'Sin calificaciones aún'
  }}];
}

// Filtrar solo los que tienen estrellas y son visibles
const calificaciones = records
  .filter(r => r.fields.ESTRELLAS && r.fields.VISIBLE === true)
  .map(r => r.fields.ESTRELLAS);

if (calificaciones.length === 0) {
  return [{ json: {
    rating: 0,
    promedio: 0,
    total: 0,
    estrellas: '☆☆☆☆☆',
    mensaje: 'Sin calificaciones visibles'
  }}];
}

// Calcular promedio
const suma = calificaciones.reduce((a, b) => a + b, 0);
const promedio = suma / calificaciones.length;
const promedioRedondeado = Math.round(promedio * 10) / 10; // 1 decimal

// Generar estrellas visuales
const estrellasLlenas = Math.round(promedio);
const estrellas = '★'.repeat(estrellasLlenas) + '☆'.repeat(5 - estrellasLlenas);

return [{ json: {
  rating: promedioRedondeado,
  promedio: promedioRedondeado,
  total: calificaciones.length,
  estrellas: estrellas,
  mensaje: `Basado en ${calificaciones.length} calificaciones`
}}];
